import numpy as np

def detect_intent(
    query_tokens: list[int],
    intent_examples: dict[str, list[list[int]]],
    embeddings: np.ndarray
) -> str:
    def mean_embed(token_ids):
        vecs = embeddings[token_ids]
        return vecs.mean(axis=0)

    def cosine_sim(a, b):
        return np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b) + 1e-12)

    # Compute query embedding
    query_emb = mean_embed(query_tokens)

    # Compute prototype per intent
    best_intent = None
    best_score = -np.inf
    for intent, examples in intent_examples.items():
        # Average of example embeddings
        proto = np.mean([mean_embed(ex) for ex in examples], axis=0)
        score = cosine_sim(query_emb, proto)
        if score > best_score:
            best_score = score
            best_intent = intent
    return best_intent
